export default function CheckingDetail() {
  const [account, setAccount] = useState(null);
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    tools.host_listAccounts({}).then((res) => {
      const accounts = res.data ?? res ?? [];
      const checking = accounts.find((a) =>
        (a.type ?? a.accountType ?? a.name ?? "").toLowerCase().includes("check")
      ) ?? accounts[0];
      if (!checking) { setLoading(false); return; }
      setAccount(checking);
      return tools.host_listAccountTransactions({ id: checking.id });
    }).then((res) => {
      if (res) {
        const txns = res.data ?? res ?? [];
        setTransactions(txns);
      }
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  if (loading) {
    return (
      <div style={{ padding: 24, fontFamily: "var(--vendo-font-family)", color: "var(--vendo-color-muted)" }}>
        Loading…
      </div>
    );
  }

  if (!account) {
    return (
      <div style={{ padding: 24, fontFamily: "var(--vendo-font-family)", color: "var(--vendo-color-muted)" }}>
        No checking account found.
      </div>
    );
  }

  const balanceCents = account.balanceCents ?? account.balance ?? 0;
  const accountNumber = account.accountNumber ?? account.number ?? account.mask
    ? `••••${account.mask ?? ""}`
    : account.id;

  const statusTone = (s) => {
    if (!s) return "neutral";
    const v = s.toLowerCase();
    if (v === "completed" || v === "settled" || v === "posted") return "success";
    if (v === "pending") return "neutral";
    if (v === "failed" || v === "declined") return "danger";
    return "neutral";
  };

  return (
    <div style={{ fontFamily: "var(--vendo-font-family)", display: "grid", gap: 20 }}>
      {/* Hero balance */}
      <div style={{
        background: "var(--vendo-color-surface)",
        border: "1px solid var(--vendo-color-border)",
        borderRadius: "var(--vendo-radius-large)",
        padding: "28px 24px",
        display: "grid",
        gap: 6
      }}>
        <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", letterSpacing: "0.02em" }}>
          {account.name ?? "Checking account"}
        </div>
        <div style={{ fontSize: 40, fontWeight: 700, color: "var(--vendo-color-text)", letterSpacing: "-0.02em" }}>
          {fmt.money(balanceCents)}
        </div>
        <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", marginTop: 4 }}>
          Account {accountNumber}
        </div>
      </div>

      {/* Transactions */}
      <div style={{
        background: "var(--vendo-color-surface)",
        border: "1px solid var(--vendo-color-border)",
        borderRadius: "var(--vendo-radius-large)",
        overflow: "hidden"
      }}>
        <div style={{ padding: "16px 20px 12px", borderBottom: "1px solid var(--vendo-color-border)" }}>
          <span style={{ fontSize: 14, fontWeight: 600, color: "var(--vendo-color-text)" }}>
            Recent transactions
          </span>
        </div>
        {transactions.length === 0 ? (
          <div style={{ padding: "24px 20px", color: "var(--vendo-color-muted)", fontSize: 14 }}>
            No transactions yet.
          </div>
        ) : (
          <div>
            {transactions.map((txn, i) => {
              const amountCents = txn.amountCents ?? txn.amount ?? 0;
              const isDebit = amountCents < 0;
              const status = txn.status ?? txn.state ?? "";
              const tone = statusTone(status);
              const toneColor = tone === "success"
                ? "#067647"
                : tone === "danger"
                ? "var(--vendo-color-danger)"
                : "var(--vendo-color-muted)";

              return (
                <div key={txn.id ?? i} style={{
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "space-between",
                  padding: "13px 20px",
                  borderBottom: i < transactions.length - 1 ? "1px solid var(--vendo-color-border)" : "none",
                  gap: 12
                }}>
                  <div style={{ display: "grid", gap: 2, flex: 1, minWidth: 0 }}>
                    <div style={{
                      fontSize: 14,
                      fontWeight: 500,
                      color: "var(--vendo-color-text)",
                      whiteSpace: "nowrap",
                      overflow: "hidden",
                      textOverflow: "ellipsis"
                    }}>
                      {txn.description ?? txn.merchant ?? txn.name ?? "Transaction"}
                    </div>
                    <div style={{ fontSize: 12, color: "var(--vendo-color-muted)" }}>
                      {txn.date ? fmt.dateTime(txn.date) : txn.createdAt ? fmt.dateTime(txn.createdAt) : ""}
                    </div>
                  </div>
                  <div style={{ display: "flex", alignItems: "center", gap: 10, flexShrink: 0 }}>
                    {status ? (
                      <span style={{
                        fontSize: 11,
                        fontWeight: 500,
                        color: toneColor,
                        background: tone === "success" ? "#ECFDF3" : tone === "danger" ? "#FEF3F2" : "#F5F5F4",
                        borderRadius: "var(--vendo-radius-small)",
                        padding: "2px 8px",
                        textTransform: "capitalize"
                      }}>
                        {status}
                      </span>
                    ) : null}
                    <div style={{
                      fontSize: 14,
                      fontWeight: 600,
                      color: "var(--vendo-color-text)",
                      textAlign: "right",
                      minWidth: 72
                    }}>
                      {isDebit ? "−" : "+"}{fmt.money(Math.abs(amountCents))}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}
